package jetbrains.mps.baseLanguage.unitTest.execution.server;

/*Generated by MPS */

import java.io.IOException;
import java.util.Arrays;
import java.util.List;

/**
 * Command-line front-end to launch BTestCase or JUnit3/JUnit4 ClassConcept without need for MPS instance/environment
 * XXX Unfortunate name, no idea what 'default' refers to.
 */
public class DefaultTestExecutor extends JUnitTestExecutor {
  public static final int EXIT_CODE_FOR_EXCEPTION = -12345;
  public static final String JUNIT5_OPTION = "-junit5";

  public DefaultTestExecutor(TestsContributor testsContributor) {
    super(testsContributor);
  }

  /**
   * Called when BTestCase or JUnit3/JUnit4 ClassConcept is executed without need for MPS instance/environment
   */
  public static void main(String[] args) throws Exception {
    DefaultTestExecutor executor;
    if (hasJUnit5Option(args)) {
      executor = new DefaultTestExecutor(new JUnit5CmdlineTestContributor(skipJUnit5Option(args)));

    } else {
      executor = new DefaultTestExecutor(new CommandLineTestsContributor(args));
    }
    try {
      executor.run();
    } finally {
      executor.exit();
    }
  }

  protected static boolean hasJUnit5Option(String[] args) throws IOException {
    return Arrays.stream(args).anyMatch((String arg) -> JUNIT5_OPTION.equals(arg));
  }

  protected static String[] skipJUnit5Option(String[] args) throws IOException {
    List<String> skip = Arrays.stream(args).filter((String arg) -> !(JUNIT5_OPTION.equals(arg))).toList();
    return skip.toArray(new String[skip.size()]);
  }


  protected void run() {
    try {
      init();
      execute();
    } catch (Throwable t) {
      processThrowable(t);
    } finally {
      dispose();
    }
  }

  @Override
  protected void processThrowable(Throwable t) {
    super.processThrowable(t);
    t.printStackTrace(System.err);
  }

  protected void exit() {
    if (getExecutionError() != null) {
      System.exit(EXIT_CODE_FOR_EXCEPTION);
    } else {
      // we don't expect test cancellation requests here
      System.exit(getFailureCount());
    }
  }
}
